/* AUTO-BUILT bundle — tier-4 craft-perspective lenses. Source: analysis/{eye_rhymes,prosody,perspectives/*,perspectives}.js
   Rebuild: node build/build_perspectives.js   (do NOT edit this file by hand) */

/* ===== analysis/eye_rhymes.js ===== */
/* eye_rhymes.js — archive of English "eye rhymes" (a.k.a. sight rhymes): words whose SPELLING
 * tails match but whose SOUNDS differ (love/move, though/through, good/blood…). Caused by the
 * Great Vowel Shift freezing spelling while pronunciation moved.
 *
 * Two jobs:
 *   1) PRONUNCIATION OVERRIDE — give the *real* rime-sound for tricky words so the rhyme engine
 *      stops false-positiving (love no longer "rhymes" with move).
 *   2) EYE-RHYME DETECTION — two end-words are an eye rhyme if their spelling tails match but their
 *      sound keys differ. Hypothesis (user's): a text-based AI that rhymes by spelling produces
 *      MORE eye rhymes than a human writing for the ear → an AI tell. (Validated at calibration.)
 *
 * SOUND keys are coarse rime labels (vowel-sound + coda), only needed to be internally consistent.
 * Organized by spelling family → {soundKey: [words]} for maintainability, then flattened.
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof window !== 'undefined' ? window : this);

  // family -> { soundKey : [words sharing that family-spelling AND that sound] }
  const FAMILIES = {
    ove:  { UHV:['love','dove','glove','above','shove'], OOV:['move','prove','approve','improve','remove'], OHV:['cove','wove','grove','drove','stove','clove','rove','strove'] },
    ood:  { UUD:['good','wood','hood','stood','understood'], OOD:['food','mood','brood'], UHD:['blood','flood'] },
    ive:  { IV:['give','live','forgive'], EYEV:['five','drive','alive','hive','dive','strive','arrive','survive','thrive','deprive'] },
    ind:  { IND:['wind'], EYEND:['find','mind','kind','blind','behind','remind','grind','rewind','unwind'] },
    one:  { UHN:['one','done','none'], OHN:['bone','stone','alone','phone','throne','zone','cone','tone','clone','prone'], AWN:['gone'] },
    ost:  { AWST:['cost','lost','frost'], OHST:['most','post','host','ghost','almost'] },
    ull:  { UUL:['full','bull','pull'], UHL:['dull','gull','hull','skull','lull','null'] },
    oot:  { UUT:['foot','soot'], OOT:['boot','root','shoot','loot','toot','hoot'] },
    omb:  { OHM:['comb'], OOM:['tomb','womb'], AHM:['bomb'] },   // comb=/oʊm/, tomb/womb=/uːm/, bomb=/ɒm/
    ear:  { AIR:['bear','wear','pear','swear','tear'], EER:['hear','near','fear','year','dear','clear','rear','spear','gear','appear'], ER:['earth','earn','learn','heard','search','pearl','yearn'], AR:['heart'] },
    ead:  { ED:['head','dead','bread','spread','thread','dread','instead','ahead'], EED:['bead','read','lead','plead','knead'] },
    eak:  { AYK:['break','steak'], EEK:['speak','weak','peak','leak','sneak','freak','streak','beak','creak'] },
    eat:  { AYT:['great'], EET:['eat','beat','seat','heat','meat','treat','wheat','repeat','defeat','retreat'], ET:['sweat','threat'] },
    aid:  { AYD:['paid','maid','raid','braid','afraid','laid'], ED:['said'] },
    ow:   { OH:['low','show','grow','snow','know','blow','flow','glow','slow','throw','below','window','shadow','tomorrow','sorrow'], OW:['cow','now','how','bow','brow','vow','plow','allow','somehow'] },
    our:  { OR:['four','pour','your','court','fourth'], OWR:['our','sour','hour','flour','scour','devour'], UUR:['tour'] },
    ord:  { ER:['word','world','work','worm','worth','worse','worst'], ORD:['ford','lord','cord','sword','accord','record','afford'] },
    ome:  { UHM:['come','some','become','overcome'], OHM:['home','dome','roam','foam','chrome','gnome'] },
    ough: { OH:['though','dough','although','thorough'], OO:['through'], OFF:['cough','trough'], UFF:['rough','tough','enough'], OW:['bough','drought','plough'] },
    ought:{ AWT:['ought','bought','thought','sought','brought','fought','nought'] },
  };

  // flatten -> word : soundKey  (a word may appear in multiple families; first wins — fine, keys are unique enough)
  const OVERRIDE = {};
  for (const fam in FAMILIES) for (const sk in FAMILIES[fam]) for (const w of FAMILIES[fam][sk]) if (!(w in OVERRIDE)) OVERRIDE[w] = sk;

  // family lookup: the spelling-tail bucket a word belongs to (for eye-rhyme: same family, diff sound)
  const FAMILY_OF = {};
  for (const fam in FAMILIES) for (const sk in FAMILIES[fam]) for (const w of FAMILIES[fam][sk]) if (!(w in FAMILY_OF)) FAMILY_OF[w] = fam;

  function soundKey(w){ w = String(w).toLowerCase().replace(/[^a-z]/g,''); return OVERRIDE[w] || null; }

  const api = { OVERRIDE, FAMILY_OF, FAMILIES, soundKey,
    nWords: Object.keys(OVERRIDE).length };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.EyeRhymes = api;
})();


/* ===== analysis/prosody.js ===== */
/* prosody.js — pure-JS, text-only, offline phonetic/rhythm primitives shared by every
 * craft-perspective detector. No dictionary download, no network, no LLM.
 *
 * Phonetic approach follows Hirjee & Brown (rap rhyme detection): collapse vowels to a few
 * SOUND CLASSES and match vowel sequences while ignoring consonants, so slant / internal /
 * multisyllabic rhymes are caught — not just exact end rhyme.
 *
 * Node-native (module.exports) and attaches to globalThis for the browser build.
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof window !== 'undefined' ? window : this);
  function safeReq(p){ try { return require(p); } catch(_) { return null; } }
  const SlopScore = G.SlopScore || (typeof require !== 'undefined' ? safeReq('../src/slop-core.js') : null);
  const EyeRhymes = G.EyeRhymes || (typeof require !== 'undefined' ? safeReq('./eye_rhymes.js') : null);
  function stripLabels(t){ return SlopScore && SlopScore.stripSectionLabels ? SlopScore.stripSectionLabels(String(t||'')) : String(t||''); }

  // ---- tokenizers (operate on label-stripped text) ----
  function lines(text){ return stripLabels(text).split(/\r?\n/).map(l=>l.trim()).filter(Boolean); }
  function stanzas(text){ return stripLabels(text).split(/\n\s*\n/).map(b=>b.trim()).filter(Boolean); }
  function words(line){ return (String(line).toLowerCase().match(/[a-z']+/g) || []); }
  function lastWord(line){ const w = words(line); return w.length ? w[w.length-1] : ''; }

  // ---- syllable estimate (vowel-group heuristic + exceptions) ~88-90% ----
  const SYL_EXC = { rhythm:2, every:2, evening:2, fire:1, fires:1, hour:1, hours:1, our:1, ours:1,
    people:2, business:2, beautiful:3, area:3, idea:3, being:2, doing:2, going:2, science:2,
    quiet:2, poem:2, prayer:1, choir:2, flower:2, power:2, tower:2, hire:1, wire:1, tired:1,
    fluid:2, ruin:2, real:1, really:2, family:3, memory:3, different:3, heaven:2, given:2,
    create:2, creature:2, february:3, chocolate:2, comfortable:3, interesting:3, favorite:3 };
  function syllables(w){
    w = String(w).toLowerCase().replace(/[^a-z]/g,'');
    if (!w) return 0;
    if (SYL_EXC[w] != null) return SYL_EXC[w];
    if (w.length <= 3) return 1;
    let s = w.replace(/(?:[^laeiouy]es|[^laeiouy]ed|[^laeiouy]e)$/,'');  // silent e / -ed / -es
    s = s.replace(/^y/,'');                                              // leading y = consonant
    const m = s.match(/[aeiouy]{1,2}/g);
    return Math.max(1, m ? m.length : 1);
  }
  function syllCount(line){ return words(line).reduce((a,w)=>a+syllables(w),0); }

  // ---- vowel sound classes (collapse for slant matching) ----
  // a,e,i,o,u -> A,E,I,O,U ; y -> I ; common digraphs handled by first letter (cheap approx)
  const VC = { a:'A', e:'E', i:'I', o:'O', u:'U', y:'I' };
  function vowelClass(v){ return VC[v[0]] || 'A'; }
  // sequence of vowel-classes for a word ("nation" -> "AO"? -> "A"+"O" = "AO")
  function vowelSeq(w){ return (String(w).toLowerCase().match(/[aeiouy]+/g) || []).map(vowelClass).join(''); }

  // rhymeKey = the rime of the LAST syllable: last vowel-group onward, vowels->classes.
  // "bail"->"Al", "pretend"->"End", "ale"->"E". Matches perfect AND slant end/internal rhyme.
  // orthographic rime: trailing letters from the last vowel (silent-e stripped) — the "spelling tail"
  function orthoRime(w){
    w = String(w).toLowerCase().replace(/[^a-z]/g,'');
    if (/[bcdfghjkmnpqrstvwxz]e$/.test(w) && w.length > 2) w = w.slice(0, -1);
    const m = w.match(/[aeiouy]+[^aeiouy]*$/); return m ? m[0] : '';
  }
  function rhymeKey(w){
    w = String(w).toLowerCase().replace(/[^a-z]/g,'');
    // PRONUNCIATION OVERRIDE first: eye-rhyme archive knows the *real* sound (love=UHV, move=OOV)
    if (EyeRhymes){ const sk = EyeRhymes.soundKey(w); if (sk) return 'OV:' + sk; }
    const r = orthoRime(w);
    return r.replace(/[aeiouy]+/g, v => vowelClass(v));
  }
  // eye rhyme: same spelling tail, different sound (love/move). True only when the override knows
  // the sounds actually differ — so non-archive words that simply share a tail still rhyme normally.
  function eyeRhyme(a, b){
    a = String(a).toLowerCase().replace(/[^a-z]/g,''); b = String(b).toLowerCase().replace(/[^a-z]/g,'');
    if (a === b || !a || !b) return false;
    if (orthoRime(a) !== orthoRime(b)) return false;   // must LOOK like a rhyme
    return rhymeKey(a) !== rhymeKey(b);                // but SOUND different
  }
  // multisyllabic key: vowel-class sequence of the last k syllables' worth of a line tail.
  function tailVowelSeq(line, kSyll){
    const ws = words(line); let out = []; let s = 0;
    for (let i = ws.length-1; i >= 0 && s < kSyll; i--){ const vs = vowelSeq(ws[i]); out.unshift(vs); s += Math.max(1, vs.length); }
    return out.join('');
  }
  // longest common trailing vowel-class run between two lines (multisyllabic rhyme length)
  function multiRhymeLen(a, b){
    const A = tailVowelSeq(a, 8), B = tailVowelSeq(b, 8);
    let i = A.length-1, j = B.length-1, n = 0;
    while (i >= 0 && j >= 0 && A[i] === B[j]) { n++; i--; j--; }
    return n;
  }

  // ---- crude primary-stress guess (for meter/flow variance) ----
  function stressGuess(w){
    const n = syllables(w);
    if (n <= 1) return [1];
    const a = new Array(n).fill(0);
    if (/(tion|sion|ity|ic|ical|ial|ious|graphy|ology)$/.test(w)) a[Math.max(0,n-2)] = 1;  // suffix pulls stress
    else a[n >= 3 ? n-2 : 0] = 1;                                                            // penult-ish default
    return a;
  }

  // ---- light POS by suffix / closed-class (noun/verb/adj/adv/func) ----
  const FUNC = new Set('a an the and or but if then so as of to in on at by for with from into about over under up down out off i you he she it we they me him her us them my your his its our their this that these those is am are was were be been being do does did have has had will would can could should may might must not no oh yeah la na ooh'.split(/\s+/));
  function posLite(w){
    w = String(w).toLowerCase();
    if (FUNC.has(w)) return 'F';
    if (/ly$/.test(w)) return 'ADV';
    if (/(ous|ful|less|ive|able|ible|al|ic|ish|y)$/.test(w)) return 'ADJ';
    if (/(ing|ed|s)$/.test(w) || /(ate|ize|ify)$/.test(w)) return 'V';
    return 'N';
  }

  const api = { lines, stanzas, words, lastWord, syllables, syllCount, vowelClass, vowelSeq,
    rhymeKey, orthoRime, eyeRhyme, tailVowelSeq, multiRhymeLen, stressGuess, posLite,
    mean: a => a.length ? a.reduce((x,y)=>x+y,0)/a.length : 0,
    stdev: a => { if(a.length<2) return 0; const m=a.reduce((x,y)=>x+y,0)/a.length; return Math.sqrt(a.reduce((x,y)=>x+(y-m)**2,0)/a.length); },
    entropy: counts => { const tot=counts.reduce((x,y)=>x+y,0); if(!tot) return 0; let h=0; for(const c of counts){ if(c){ const p=c/tot; h-=p*Math.log2(p);} } return h; }
  };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.Prosody = api;
})();


/* ===== analysis/perspectives/rapper.js ===== */
/* perspectives/rapper.js — the FREESTYLE RAPPER lens.
 *
 * Flowchart of computable questions a rapper asks of a lyric, each answered from text alone
 * (via prosody.js), each emitting a t4_rap_* feature + a fragment for the report string.
 * Rhyme is detected Hirjee&Brown-style: match VOWEL-CLASS sequences (ignore consonants) so
 * slant/internal/multisyllabic rhyme is caught, not just exact end rhyme.
 *
 * Direction column = our HYPOTHESIS of which way the signal leans; the trained model decides the
 * real weight. We log separation at calibration and keep only signals that earn their place.
 *
 *   Q (what a rapper notices)                 feature                 hypothesis
 *   1 How dense is the rhyming overall?        t4_rap_rhymeDensity     human↑ (rappers pack rhyme)
 *   2 Are there rhymes INSIDE lines?           t4_rap_internalRhyme    human↑
 *   3 Multisyllabic / compound rhymes?         t4_rap_multisyll        human↑ (rare in AI)
 *   4 Slant vs always-perfect rhyme?           t4_rap_slantRatio       human↑ (AI over-perfects)
 *   5 Is the end-rhyme scheme too regular?     t4_rap_schemeEntropy    human↑ (AI = rigid AABB)
 *   6 Does the flow/cadence vary?              t4_rap_flowVarianceCV   human↑ (AI = monotone lines)
 *   7 Stress/beat variance across lines?       t4_rap_stressVarCV      human↑
 *   8 Assonance play within lines?             t4_rap_assonance        human↑
 *   9 Lazy repeated END WORD as a "rhyme"?     t4_rap_repeatEndWord    AI↑ (cheap rhyme)
 *  10 Enjambment (run-on) vs end-stopped?      t4_rap_enjambment       human↑ (AI end-stops every line)
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof window !== 'undefined' ? window : this);
  const P = G.Prosody || (typeof require !== 'undefined' ? require('../prosody.js') : null);

  const orthoRime = P.orthoRime;        // perfect (same letters) vs slant (same vowel-class only)
  const STOP_END = /[.!?,;:—–-]\s*$/;   // line ends on punctuation = end-stopped

  function analyze(text){
    const L = P.lines(text);
    const nL = Math.max(1, L.length);
    const ends = L.map(P.lastWord);
    const endKeys = ends.map(P.rhymeKey);
    const syll = L.map(P.syllCount);
    const stress = L.map(l => P.words(l).reduce((a,w)=>a + P.stressGuess(w).reduce((x,y)=>x+y,0), 0));

    let internal = 0, multi = 0, assonance = 0, perfectEnd = 0, slantEnd = 0, repeatEnd = 0, enjamb = 0, eye = 0;

    for (let i = 0; i < L.length; i++){
      const ws = P.words(L[i]);
      // (2) internal rhyme: non-final words that rhyme with another word or the end word in-line
      const keys = ws.map(P.rhymeKey);
      const seen = {};
      for (let k = 0; k < keys.length; k++){
        const key = keys[k]; if (!key) continue;
        if (seen[key] !== undefined && k !== keys.length - 1) internal++;
        seen[key] = k;
      }
      // (8) assonance: repeated vowel-class anywhere in the line beyond chance
      const vc = {}; let vhits = 0;
      for (const w of ws){ for (const v of (w.match(/[aeiouy]+/g)||[])){ const c = P.vowelClass(v); if (vc[c]) vhits++; vc[c] = 1; } }
      assonance += vhits / Math.max(1, ws.length);
      // (10) enjambment: line does NOT end on punctuation
      if (ws.length && !STOP_END.test(L[i])) enjamb++;
      // end-rhyme (or EYE-rhyme) vs the previous up-to-2 lines
      for (let j = Math.max(0, i-2); j < i; j++){
        // (11) EYE RHYME: looks like a rhyme (same spelling tail) but sounds different (love/move).
        // Hypothesis: AI that rhymes by spelling does this more than a human writing for the ear.
        if (P.eyeRhyme(ends[i], ends[j])) { eye++; break; }
        if (!endKeys[i] || endKeys[i] !== endKeys[j]) continue;
        if (ends[i] === ends[j]) { repeatEnd++; }                         // same word = lazy
        else if (orthoRime(ends[i]) === orthoRime(ends[j])) perfectEnd++; // same letters + sound = perfect
        else slantEnd++;                                                  // vowel-class only = slant
        if (P.multiRhymeLen(L[i], L[j]) >= 2) multi++;                    // multisyllabic
        break;
      }
    }

    const endRhymePairs = perfectEnd + slantEnd + repeatEnd;
    // (5) scheme regularity: entropy of the end-key sequence (low = rigid/repetitive = AI-ish)
    const keyCounts = {}; for (const k of endKeys) if (k) keyCounts[k] = (keyCounts[k]||0)+1;
    const schemeEntropy = P.entropy(Object.values(keyCounts));

    const f = {
      t4_rap_rhymeDensity: (endRhymePairs + internal) / nL,
      t4_rap_internalRhyme: internal / nL,
      t4_rap_multisyll: multi / nL,
      t4_rap_slantRatio: slantEnd / Math.max(1, perfectEnd + slantEnd),
      t4_rap_schemeEntropy: schemeEntropy,
      t4_rap_flowVarianceCV: P.mean(syll) ? P.stdev(syll) / P.mean(syll) : 0,
      t4_rap_stressVarCV: P.mean(stress) ? P.stdev(stress) / P.mean(stress) : 0,
      t4_rap_assonance: assonance / nL,
      t4_rap_repeatEndWord: repeatEnd / nL,
      t4_rap_enjambment: enjamb / nL,
      t4_rap_eyeRhyme: eye / nL,
    };

    // ---- report string (panel narrative; tendencies, never verdicts) ----
    const scheme = schemeEntropy < 1.6 ? 'a rigid, repetitive rhyme scheme'
                 : schemeEntropy > 2.6 ? 'a varied, unpredictable scheme' : 'a moderately varied scheme';
    const flow = f.t4_rap_flowVarianceCV < 0.10 ? 'near-identical line lengths (flat flow)'
               : f.t4_rap_flowVarianceCV > 0.25 ? 'shifting cadence (lively flow)' : 'some cadence variation';
    const bits = [];
    bits.push(`~${f.t4_rap_rhymeDensity.toFixed(1)} rhymes/line with ${scheme}`);
    bits.push(f.t4_rap_internalRhyme > 0.15 ? 'good internal rhyme' : 'little internal rhyme');
    if (f.t4_rap_multisyll > 0.1) bits.push('some multisyllabic rhyme');
    bits.push(flow);
    let tip;
    if (f.t4_rap_internalRhyme < 0.1) tip = 'try threading a rhyme inside the line, not only at the end';
    else if (f.t4_rap_flowVarianceCV < 0.1) tip = 'vary the line lengths to break the metronome feel';
    else if (f.t4_rap_slantRatio < 0.15 && endRhymePairs > 2) tip = 'swap a perfect rhyme for a slant rhyme to sound less sing-song';
    else if (f.t4_rap_repeatEndWord > 0.15) tip = 'you rhyme a word with itself — find a fresh rhyme';
    else tip = 'the flow has life — push one bar into a multisyllabic rhyme';

    return { features: f, report: `Rapper's ear: ${bits.join(', ')}. ${tip}.`,
      score: clamp01(0.5 + 0.25*(f.t4_rap_repeatEndWord*3 - f.t4_rap_internalRhyme*2 - f.t4_rap_flowVarianceCV - f.t4_rap_slantRatio)) };
  }
  function clamp01(x){ return Math.max(0, Math.min(1, x)); }

  const api = { analyze };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.PerspRapper = api;
})();


/* ===== analysis/perspectives/poet.js ===== */
/* perspectives/poet.js — the POET lens: imagery, the senses, sound, and the turn.
 *
 * What a poet asks: Is this SEEN or just stated? Which senses? Fresh images or stock? Does the
 * sound do work (alliteration/assonance)? Is there a TURN (volta)? Pure-JS, text-only.
 *
 *   Q                                  feature                  hypothesis
 *   1 concrete vs abstract nouns        t4_poet_concreteRatio    human↑ (AI abstracts)
 *   2 how many of the 5 senses          t4_poet_senseDiversity   human↑ (AI sight-only)
 *   3 sight-share of sensory words      t4_poet_sightShare       AI↑
 *   4 figurative density (simile/metaphor) t4_poet_figurative     ~ (both; quality differs)
 *   5 stock/cliché imagery share        t4_poet_stockImagery     AI↑ (shadows/embers/neon)
 *   6 alliteration play                 t4_poet_alliteration     human↑
 *   7 abstraction w/o concrete anchor   t4_poet_ungrounded       AI↑
 *   8 a turn / volta                    t4_poet_volta            human↑ (AI rarely turns)
 *   9 imageable-noun density            t4_poet_imageDensity     human↑
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof window !== 'undefined' ? window : this);
  const P = G.Prosody || (typeof require !== 'undefined' ? require('../prosody.js') : null);

  const ABSTRACT = new Set(('love hate pain joy sorrow soul soulmate spirit heart hearts dream dreams hope hopes fear fears '+
    'time life death destiny fate freedom truth lies memory memories eternity infinity forever peace war faith doubt desire '+
    'passion emotion emotions feeling feelings thought thoughts mind beauty darkness silence chaos heaven hell glory shame '+
    'pride grief loss longing yearning bliss agony despair wonder magic miracle fantasy reality dream serenity karma energy '+
    'essence existence meaning purpose courage strength weakness sin grace mercy wisdom').split(/\s+/));
  const STOCK = new Set(('neon shadow shadows ember embers ash ashes abyss silhouette crimson velvet ethereal cascade infinity '+
    'eternity symphony kaleidoscope labyrinth tapestry luminous celestial cosmic radiant stardust moonlight starlight '+
    'whisper whispers echo echoes horizon skyline streetlight streetlights flame flames flicker glimmer shimmer veins '+
    'phoenix demons angels void fragments').split(/\s+/));
  const SENSE = {
    sight:  new Set('see saw seen seeing look looked looking watch watched eyes eye light lights bright dim glow glowing shine shining gleam color colors red blue green gold golden gray grey dark sight stare gaze flash'.split(/\s+/)),
    sound:  new Set('hear heard hearing listen sound sounds voice voices whisper whispers sing sang singing song echo echoes loud quiet noise ring rang hum humming buzz music silence shout scream call rhythm beat drum'.split(/\s+/)),
    touch:  new Set('touch touched feel felt skin warm warmth cold cool soft hard rough smooth hold held hand hands grip press shiver tremble embrace kiss caress sting burn ache'.split(/\s+/)),
    taste:  new Set('taste tasted sweet bitter sour salt salty honey wine sugar sip drink swallow tongue lips'.split(/\s+/)),
    smell:  new Set('smell smelled scent perfume smoke rose roses fragrance breath incense'.split(/\s+/)),
  };
  const SIMILE = /\b(like|as)\s+(a|an|the)?\s*[a-z]/gi;
  const COPULA = /\b(is|are|was|were|am)\s+(a|an|the)\s+[a-z]+/gi;
  const POS = new Set('love hope light warm bright joy alive free smile shine gold beautiful peace home together rise dawn sun'.split(/\s+/));
  const NEG = new Set('pain cry tears dark cold alone lost broken fall fear empty gone die death goodbye rain grave hurt ache scar'.split(/\s+/));
  const TURN = /\b(but|yet|still|though|until|now|then|suddenly|instead|however)\b/i;

  function analyze(text){
    const L = P.lines(text), nL = Math.max(1, L.length);
    const toks = []; for (const l of L) for (const w of P.words(l)) toks.push(w);
    const nT = Math.max(1, toks.length);

    let nouns=0, concreteN=0, image=0, stock=0;
    const senseCount = {sight:0,sound:0,touch:0,taste:0,smell:0};
    for (const w of toks){
      if (P.posLite(w) === 'N'){ nouns++; if (!ABSTRACT.has(w)){ concreteN++; if (!STOCK.has(w)) image++; } }
      if (STOCK.has(w)) stock++;
      for (const s in SENSE) if (SENSE[s].has(w)) senseCount[s]++;
    }
    const sensesPresent = Object.values(senseCount).filter(c => c>0).length;
    const senseTotal = Object.values(senseCount).reduce((a,b)=>a+b,0);

    const similes = (text.match(SIMILE)||[]).length;
    const copulas = (text.match(COPULA)||[]).length;

    // alliteration: adjacent content words sharing first consonant
    let allit = 0;
    for (const l of L){ const ws = P.words(l).filter(w=>w.length>2); for (let i=1;i<ws.length;i++){
      const a=ws[i-1][0], b=ws[i][0]; if (a===b && !'aeiou'.includes(a)) allit++; } }

    // ungrounded: lines whose words are abstract-heavy with no concrete noun
    let ungrounded=0; for (const l of L){ const ws=P.words(l); let abs=0,con=0;
      for (const w of ws){ if (ABSTRACT.has(w)) abs++; else if (P.posLite(w)==='N') con++; }
      if (abs>=1 && con===0 && ws.length>=3) ungrounded++; }

    // volta: sentiment flip between first and second half, OR a turn-word starting a late line
    const half = Math.floor(L.length/2) || 1;
    const sent = seg => { let p=0,n=0; for (const w of P.words(seg.join(' '))){ if(POS.has(w))p++; if(NEG.has(w))n++; } return (p-n)/Math.max(1,p+n); };
    const flip = Math.abs(sent(L.slice(0,half)) - sent(L.slice(half))) > 0.5 ? 1 : 0;
    const lateTurn = L.slice(half).some(l => TURN.test(l.trim().split(/\s+/).slice(0,2).join(' '))) ? 1 : 0;
    const volta = Math.max(flip, lateTurn);

    const f = {
      t4_poet_concreteRatio: concreteN / Math.max(1, nouns),
      t4_poet_imageDensity: image / nT,
      t4_poet_senseDiversity: sensesPresent / 5,
      t4_poet_sightShare: senseTotal ? senseCount.sight / senseTotal : 0,
      t4_poet_figurative: (similes + copulas) / nL,
      t4_poet_stockImagery: stock / Math.max(1, image + stock),
      t4_poet_alliteration: allit / nL,
      t4_poet_ungrounded: ungrounded / nL,
      t4_poet_volta: volta,
    };

    const senseNames = Object.keys(senseCount).filter(s=>senseCount[s]>0);
    const bits = [];
    bits.push(f.t4_poet_concreteRatio > 0.6 ? 'grounded in concrete images' : 'leans abstract');
    bits.push(senseNames.length <= 1 ? `mostly ${senseNames[0]||'no'} imagery` : `${senseNames.length} senses (${senseNames.join('/')})`);
    if (f.t4_poet_stockImagery > 0.3) bits.push('relies on stock images');
    bits.push(volta ? 'has a turn' : 'no real turn');
    let tip;
    if (f.t4_poet_concreteRatio < 0.5) tip = 'replace one abstract feeling with a specific seen detail';
    else if (sensesPresent <= 1) tip = 'bring in another sense — a sound, a smell, a texture';
    else if (f.t4_poet_stockImagery > 0.3) tip = 'swap a stock image (shadows/embers) for something only this song would say';
    else if (!volta) tip = 'add a turn — let the last verse complicate the first';
    else tip = 'the imagery works — find one fresher metaphor to anchor it';

    return { features: f, report: `Poet's eye: ${bits.join(', ')}. ${tip}.`,
      score: clamp01(0.5 + 0.2*(f.t4_poet_stockImagery + f.t4_poet_ungrounded + f.t4_poet_sightShare - f.t4_poet_concreteRatio - f.t4_poet_senseDiversity - volta*0.5)) };
  }
  function clamp01(x){ return Math.max(0, Math.min(1, x)); }
  const api = { analyze };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.PerspPoet = api;
})();


/* ===== analysis/perspectives/wit.js ===== */
/* perspectives/wit.js — the INTELLECTUAL / WIT lens.
 *
 * Approximates "cleverness" without semantics/LLM, via computable proxies:
 *   - DOMAIN FUSION: a witty line pulls vocabulary from multiple distinct semantic DOMAINS at once.
 *     Queen, "burning(HEAT) through the sky(SPACE)… two hundred degrees(SCIENCE)… Mr Fahrenheit(SCI-name)"
 *     = a 3-domain blend. AI mood-stacks within ONE domain; wit fuses domains. (centerpiece)
 *   - HOMOPHONE density: pun POTENTIAL (their/there, sun/son, knight/night…).
 *   - POLYPTOTON: same root in different forms nearby ("call me / they call", "burn/burning") = play.
 *   - ALLUSION: named cultural entities (mid-line proper nouns) — wit references the world.
 *   - LEXICAL RARITY: share of words outside the common-1000 + word length = vocabulary reach.
 * Full pun/double-entendre detection needs semantics (out of scope) — these are honest proxies; the
 * model + calibration decide which earn their place.
 *
 *   Q                                   feature                  hyp.
 *   1 multiple domains fused per line     t4_wit_domainFusion      human/wit↑
 *   2 peak domain blend (best line)       t4_wit_domainPeak        human/wit↑
 *   3 lines blending >=3 domains          t4_wit_blendRate         human/wit↑
 *   4 homophone (pun-potential) density   t4_wit_homophone         human/wit↑
 *   5 polyptoton (root play)              t4_wit_polyptoton        human/wit↑
 *   6 allusion / named entities           t4_wit_allusion          human/wit↑
 *   7 rare-vocabulary share               t4_wit_lexRare           human/wit↑
 *   8 mean syllables / content word       t4_wit_wordLength        human/wit↑
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof require !== 'undefined' ? globalThis : this);
  const P = G.Prosody || (typeof require !== 'undefined' ? require('../prosody.js') : null);
  function safeReq(p){ try { return require(p); } catch(_) { return {}; } }
  const CW = G.SlopCommon || (typeof require !== 'undefined' ? safeReq('../../src/common_words.js') : {});
  const COMMON = (CW && CW.TOP1000 instanceof Set) ? CW.TOP1000 : new Set((CW && CW.TOP1000) || []);
  // stock/cliché imagery words — these inflate "domain fusion" without being witty, so EXCLUDE them.
  const STOCK = new Set(('neon shadow shadows ember embers ash ashes abyss silhouette crimson velvet ethereal '+
    'symphony luminous celestial cosmic radiant stardust moonlight starlight whisper whispers echo echoes horizon '+
    'skyline streetlight streetlights flame flames flicker glimmer shimmer veins phoenix demons angels void fragments '+
    'storm thunder lightning midnight rain tears soul heart heartbeat darkness').split(/\s+/));
  // "hard" / concrete-technical domains: where specificity & wit live; cliché lyrics avoid them.
  const HARD = new Set(['science','money','crime','tech','war','space','speed','royalty']);
  const SOFT = new Set(['love','body','time','light','heat','nature','water','cold','music','religion']);

  // ~18 semantic domains (compact, lyric-relevant). A word can sit in several.
  const DOMAINS = {
    heat:    'fire flame flames burn burning burned blaze heat hot scorch ember embers ash smoke degrees fahrenheit celsius melt inferno furnace spark sweat'.split(' '),
    cold:    'ice cold frost freeze frozen snow winter chill numb shiver glacier'.split(' '),
    space:   'sky star stars moon sun cosmos cosmic galaxy orbit planet comet meteor rocket heaven atmosphere gravity universe nebula astronaut'.split(' '),
    speed:   'fast speed run race fly rush dash bolt sprint accelerate velocity zoom chase racing engine highway'.split(' '),
    science: 'degrees temperature atom atoms chemical formula equation experiment data measure unit molecule physics gravity electric voltage element laboratory'.split(' '),
    money:   'money cash gold dollar dollars coin coins rich poor bank debt price cost diamond fortune wealth broke pay paid bill'.split(' '),
    war:     'war fight battle gun guns knife blood soldier weapon bomb attack kill army shield sword trigger trench enemy'.split(' '),
    body:    'heart blood bone bones skin veins hand hands eyes lips lungs breath pulse spine flesh teeth nerve'.split(' '),
    nature:  'river ocean sea mountain tree trees forest flower rain wind earth stone field garden leaf root soil valley'.split(' '),
    love:    'love kiss desire lover romance passion sweetheart embrace heartbreak crush affection'.split(' '),
    religion:'god heaven hell soul pray prayer church angel devil sin saint holy faith sacred gospel cross worship'.split(' '),
    royalty: 'king queen crown throne royal reign rule empire ruler prince princess castle palace kingdom'.split(' '),
    time:    'time clock hour hours day night year years moment forever yesterday tomorrow second minute past future midnight dawn'.split(' '),
    crime:   'crime law police jail prison court judge guilty steal thief bail handcuffs verdict felony'.split(' '),
    music:   'song sing music note melody rhythm beat drum guitar voice tune chord chorus stage'.split(' '),
    tech:    'machine wire circuit screen phone signal code wheel motor electric battery digital pixel network'.split(' '),
    water:   'water wave waves flood drown tide swim drip pour stream rain ocean sea'.split(' '),
    light:   'light dark shadow shadows bright shine glow dim lamp neon flicker glimmer beam'.split(' '),
  };
  const WORD2DOM = {};
  for (const d in DOMAINS) for (const w of DOMAINS[d]) (WORD2DOM[w] = WORD2DOM[w] || []).push(d);

  // common homophones (pun potential) — compact high-frequency set
  const HOMOPHONE = new Set(('their there theyre to too two sea see knight night write right wright flower flour sun son '+
    'hear here hour our by buy bye won one road rode rowed bear bare break brake cell sell deer dear eye i aye '+
    'fair fare for four fore great grate hole whole hour our knew new know no mail male meat meet peace piece '+
    'plane plain rain reign rein role roll sail sale scene seen steal steel tail tale tide tied wait weight '+
    'way weigh weak week wood would your youre maid made made pair pear pare red read blue blew threw through '+
    'die dye soul sole toe tow waste waist').split(/\s+/));

  function stem(w){ return w.replace(/(ing|edly|ed|ly|ers|er|est|s|tion|ness|ment)$/,''); }

  function analyze(text){
    const L = P.lines(text), nL = Math.max(1, L.length);
    const toks = []; for (const l of L) for (const w of P.words(l)) toks.push(w);
    const nT = Math.max(1, toks.length);

    // domain fusion per line — EXCLUDE stock/cliché words (so mood-stacking != wit)
    let fusionSum = 0, peak = 0, blendLines = 0, crossReg = 0, hardHits = 0;
    for (const l of L){
      const doms = new Set();
      for (const w of P.words(l)){ if (STOCK.has(w)) continue; if (WORD2DOM[w]) for (const d of WORD2DOM[w]){ doms.add(d); if (HARD.has(d)) hardHits++; } }
      fusionSum += doms.size; if (doms.size > peak) peak = doms.size; if (doms.size >= 3) blendLines++;
      // cross-register: a line that mixes a HARD/technical domain with a SOFT/emotional one
      let h=false, s=false; for (const d of doms){ if (HARD.has(d)) h=true; if (SOFT.has(d)) s=true; }
      if (h && s) crossReg++;
    }

    // homophones
    let homo = 0; for (const w of toks) if (HOMOPHONE.has(w)) homo++;

    // polyptoton: same stem, different surface form, anywhere
    const byStem = {}; for (const w of toks){ if (w.length < 3) continue; const s = stem(w); (byStem[s] = byStem[s] || new Set()).add(w); }
    let poly = 0; for (const s in byStem) if (byStem[s].size >= 2) poly += byStem[s].size - 1;

    // allusion: mid-line capitalized words (proper nouns), not line-start, not "I"
    let allusion = 0;
    for (const l of L){ const raw = l.split(/\s+/); for (let i=1;i<raw.length;i++){ const t=raw[i];
      if (/^[A-Z][a-z]{2,}$/.test(t) && !/^(I|Im|Id|Ive|Ill)$/.test(t)) allusion++; } }

    // lexical rarity + word length (content words only)
    let content=0, rare=0, syll=0;
    for (const w of toks){ if (P.posLite(w)==='F' || w.length<3) continue; content++; if (!COMMON.has(w)) rare++; syll += P.syllables(w); }

    const f = {
      t4_wit_domainFusion: fusionSum / nL,
      t4_wit_domainPeak: peak,
      t4_wit_blendRate: blendLines / nL,
      t4_wit_crossRegister: crossReg / nL,
      t4_wit_hardDomain: hardHits / nT,
      t4_wit_homophone: homo / nT,
      t4_wit_polyptoton: poly / nL,
      t4_wit_allusion: allusion / nL,
      t4_wit_lexRare: content ? rare / content : 0,
      t4_wit_wordLength: content ? syll / content : 0,
    };

    const bits = [];
    bits.push(f.t4_wit_domainFusion > 1.3 ? 'fuses ideas across domains' : 'stays in one idea-domain per line');
    if (peak >= 3) bits.push(`one line blends ${peak} domains`);
    if (f.t4_wit_polyptoton > 0.1) bits.push('plays with word roots');
    if (f.t4_wit_allusion > 0.05) bits.push('makes outside references');
    bits.push(f.t4_wit_lexRare > 0.45 ? 'reaches for less common words' : 'common vocabulary');
    let tip;
    if (f.t4_wit_domainFusion < 1.1) tip = 'try a line that collides two worlds (a feeling described in money, weather, or science terms)';
    else if (f.t4_wit_homophone < 0.01) tip = 'a pun or double-meaning would add a wink';
    else if (f.t4_wit_lexRare < 0.4) tip = 'one surprising, precise word can lift a whole line';
    else tip = 'the wordplay is live — push one image into a double meaning';

    return { features: f, report: `Wit: ${bits.join(', ')}. ${tip}.`,
      score: clamp01(0.5 - 0.15*(f.t4_wit_domainFusion - 1 + f.t4_wit_polyptoton*3 + f.t4_wit_homophone*10 + (f.t4_wit_lexRare-0.4))) };
  }
  function clamp01(x){ return Math.max(0, Math.min(1, x)); }
  const api = { analyze, DOMAINS };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.PerspWit = api;
})();


/* ===== analysis/perspectives/psychologist.js ===== */
/* perspectives/psychologist.js — the PSYCHOLOGIST lens: is there a real mind, and does the song
 * build ONE coherent thought, or stack disconnected moods?
 *
 * Centerpiece (user's "Somebody to Love" insight): a human delivers sentences IN ORDER, each line
 * carrying the last into one complete thought, talking to the listener — while AI mood-stacks
 * pretty but disconnected lines. Text-only proxy (no embeddings): LEXICAL COHESION between adjacent
 * lines (shared content stems / carried referent) = the narrative thread.
 *
 *   Q                                    feature                    hyp.
 *   1 do adjacent lines connect (thread)?  t4_psy_cohesion           human↑ (AI = non-sequitur stack)
 *   2 subject/pronoun continuity?          t4_psy_subjectContinuity  human↑
 *   3 interiority (a modeled mind)?         t4_psy_interiority        ~ (mental-state verbs)
 *   4 specific vs placeholder emotion?      t4_psy_emoGranularity     human↑
 *   5 ambivalence / mixed feeling?          t4_psy_ambivalence        human↑ (psych realism)
 *   6 direct address to a listener?         t4_psy_directAddress      human↑ ("talking to the audience")
 *   7 agency (I-did active verbs)?          t4_psy_agency             human↑
 *   8 placeholder-emotion density           t4_psy_placeholder        AI↑
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof require !== 'undefined' ? globalThis : this);
  const P = G.Prosody || (typeof require !== 'undefined' ? require('../prosody.js') : null);
  const T3 = G.SlopTier3 || (typeof require !== 'undefined' ? safeReq('../tier3_detectors.js') : null);
  function safeReq(p){ try { return require(p); } catch(_) { return null; } }

  const MENTAL = new Set(('think thought thinking know knew knowing feel felt realize realized realise wonder wondered '+
    'remember remembered forget forgot forgotten want wanted wish wished hope hoped fear feared believe believed doubt '+
    'doubted understand understood regret regretted imagine imagined suppose decide decided meant pretend pretended '+
    'notice noticed assume guess used wonder consider learned learn').split(/\s+/));
  const SPECIFIC_EMO = new Set(('ashamed shame jealous jealousy relieved relief embarrassed proud pride lonely loneliness '+
    'anxious bitter bitterness grateful gratitude nostalgic guilty guilt resentful envious content restless homesick '+
    'furious terrified hopeful disappointed humiliated betrayed insecure awkward reluctant tender vengeful smug').split(/\s+/));
  const PLACEHOLDER_EMO = new Set(('broken shattered lost empty hollow numb pain painful hurt aching ache torn falling '+
    'drowning breaking fading cold dark darkness alone lonely tears crying').split(/\s+/));
  const FIRST = new Set('i me my mine myself we us our ours ourselves'.split(/\s+/));
  const SECOND = new Set('you your yours yourself yourselves'.split(/\s+/));
  const THIRD = new Set('he she they him her them his their hers theirs it its'.split(/\s+/));
  const VOCATIVE = new Set('baby babe darling honey sweetheart girl boy love dear man brother sister mama mister'.split(/\s+/));

  function contentStems(line){
    const s = new Set();
    for (const w of P.words(line)) if (w.length > 2 && P.posLite(w) !== 'F') s.add(stem(w));
    return s;
  }
  function stem(w){ return w.replace(/(ing|edly|ed|ly|ers|er|est|s|tion|ness|ment)$/,''); }
  function jacc(a,b){ if(!a.size||!b.size) return 0; let i=0; for(const x of a) if(b.has(x)) i++; return i/(a.size+b.size-i); }

  function analyze(text){
    const L = P.lines(text), nL = Math.max(1, L.length);
    const toks = []; for (const l of L) for (const w of P.words(l)) toks.push(w);
    const nT = Math.max(1, toks.length);

    // (1) adjacent-line lexical cohesion = the carried thread
    let cohes = 0, pairs = 0;
    const sets = L.map(contentStems);
    for (let i=1;i<L.length;i++){ cohes += jacc(sets[i], sets[i-1]); pairs++; }
    const cohesion = pairs ? cohes/pairs : 0;

    // (2) subject/pronoun continuity: dominant person carried line-to-line
    function person(line){ let f=0,s=0,t=0; for(const w of P.words(line)){ if(FIRST.has(w))f++; if(SECOND.has(w))s++; if(THIRD.has(w))t++; } return f>=s&&f>=t&&f>0?'1':s>=t&&s>0?'2':t>0?'3':''; }
    const persons = L.map(person).filter(Boolean);
    let same=0; for(let i=1;i<persons.length;i++) if(persons[i]===persons[i-1]) same++;
    const subjectContinuity = persons.length>1 ? same/(persons.length-1) : 0;

    let mental=0, spec=0, place=0, first=0, second=0, agency=0;
    for (let i=0;i<toks.length;i++){ const w=toks[i];
      if (MENTAL.has(w)) mental++;
      if (SPECIFIC_EMO.has(w)) spec++;
      if (PLACEHOLDER_EMO.has(w)) place++;
      if (FIRST.has(w)) first++;
      if (SECOND.has(w)) second++;
      // agency: "I/we" immediately followed by an action verb
      if ((w==='i'||w==='we') && i+1<toks.length){ const nx=toks[i+1]; if (P.posLite(nx)==='V' && !MENTAL.has(nx)) agency++; }
    }

    // (5) ambivalence: mixed feeling — both a positive and negative emotion word in one line, or a contradiction marker
    let ambiv=0; const POSW=/\b(love|happy|smile|joy|warm|hope|alive|free|together)\b/i, NEGW=/\b(hate|sad|cry|pain|cold|alone|lost|fear|hurt|broken)\b/i;
    for (const l of L){ if ((POSW.test(l)&&NEGW.test(l)) || /\b(but|yet|still|though|even though)\b/i.test(l)) ambiv++; }

    // (6) direct address: 2nd-person density + vocatives + questions
    let voc=0, q=0; for (const l of L){ const ws=P.words(l); if (ws.some(w=>VOCATIVE.has(w))) voc++; if (/\?/.test(l)) q++; }
    const directAddress = (second/nT) + (voc/nL)*0.5 + (q/nL)*0.5;

    const f = {
      t4_psy_cohesion: cohesion,
      t4_psy_subjectContinuity: subjectContinuity,
      t4_psy_interiority: mental/nT,
      t4_psy_emoGranularity: spec/Math.max(1, spec+place),
      t4_psy_ambivalence: ambiv/nL,
      t4_psy_directAddress: directAddress,
      t4_psy_agency: agency/nL,
      t4_psy_placeholder: place/nT,
    };

    const bits = [];
    bits.push(cohesion > 0.12 ? 'lines build on each other (a real thread)' : 'lines feel like separate images');
    bits.push(f.t4_psy_emoGranularity > 0.4 ? 'names specific feelings' : 'leans on placeholder emotions');
    if (f.t4_psy_directAddress > 0.08) bits.push('talks directly to someone');
    if (f.t4_psy_ambivalence > 0.15) bits.push('holds mixed feelings');
    let tip;
    if (cohesion < 0.08) tip = 'let each line answer the one before it, so the verse tells one moving thought';
    else if (f.t4_psy_emoGranularity < 0.3) tip = 'name the exact feeling (ashamed, relieved, jealous) instead of "broken/lost"';
    else if (f.t4_psy_agency < 0.1) tip = 'put yourself in motion — "I did X" beats "everything was Y"';
    else tip = 'the interior life is there — add one contradictory feeling to make it human';

    return { features: f, report: `Psychologist: ${bits.join(', ')}. ${tip}.`,
      score: clamp01(0.5 + 0.2*(f.t4_psy_placeholder*4 - cohesion*3 - f.t4_psy_emoGranularity - f.t4_psy_directAddress*2)) };
  }
  function clamp01(x){ return Math.max(0, Math.min(1, x)); }
  const api = { analyze };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.PerspPsych = api;
})();


/* ===== analysis/perspectives/philosopher.js ===== */
/* perspectives/philosopher.js — the PHILOSOPHER lens: is there an IDEA being reasoned, and do the
 * lines follow each other in logical/temporal ORDER (vs a stack of standalone moods)?
 *
 * This is where the user's "Somebody to Love" coherence idea is tested as a better text-only proxy:
 * SEQUENTIAL CONNECTIVES — lines that begin with / contain logical-temporal links (but, so, because,
 * then, when, until) carry a thought forward, where AI mood-stacking drops standalone images.
 *
 *   Q                                  feature                      hyp.
 *   1 lines link in logical order?       t4_phil_sequentialFlow      human↑ (line-initial connectives)
 *   2 overall connective density         t4_phil_connectives         human↑
 *   3 argument markers (tension)         t4_phil_argMarkers          human↑ (reuse tier3)
 *   4 conditionals (if/when X then Y)    t4_phil_conditionals        human↑
 *   5 cause→effect chains                t4_phil_causal              human↑
 *   6 paradox / antithesis               t4_phil_paradox             human↑
 *   7 rhetorical questions               t4_phil_rhetoricalQ         human↑
 *   8 universals grounded in particulars t4_phil_groundedIdea        human↑ (idea + instance)
 *   9 bare universals (unanchored)       t4_phil_bareUniversal       AI↑ (everyone/always w/o instance)
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof require !== 'undefined' ? globalThis : this);
  const P = G.Prosody || (typeof require !== 'undefined' ? require('../prosody.js') : null);

  const CONNECT = new Set('but so because therefore then when after before until while since if though although yet however instead unless whereas once and or nor for'.split(/\s+/));
  const SEQ_START = new Set('but so because then when after before until while since though although yet however instead and now'.split(/\s+/)); // line-initial = continues a thought
  const CAUSAL = /\b(because|so that|therefore|so i|so we|that is why|that's why|which is why|so you|cause i|cause we)\b/gi;
  const COND = /\b(if|when|whenever|unless|as long as|once)\s+\w+/gi;
  const RQ = /\?/g;
  const PARADOX = /\b(the more .* the (more|less)|not .* but|more than .* less than|half .* half|both .* and)\b/i;
  const UNIVERSAL = new Set('everyone everybody everything always never nobody nothing none all every anyone forever everywhere nowhere anything'.split(/\s+/));

  function analyze(text){
    const L = P.lines(text), nL = Math.max(1, L.length);
    const toks = []; for (const l of L) for (const w of P.words(l)) toks.push(w);
    const nT = Math.max(1, toks.length);

    let seqStart = 0, connect = 0, universal = 0, grounded = 0, paradox = 0;
    for (const l of L){
      const ws = P.words(l);
      if (ws.length && SEQ_START.has(ws[0])) seqStart++;
      for (const w of ws){ if (CONNECT.has(w)) connect++; }
      // universal grounded if line also has a concrete referent (year/number/proper noun/specific)
      const hasUniv = ws.some(w => UNIVERSAL.has(w));
      const hasParticular = /\b(19[0-9]{2}|20[0-2][0-9]|\d{1,4})\b/.test(l) || /(^|\s)[A-Z][a-z]{2,}/.test(l.replace(/^[A-Z]/,''));
      if (hasUniv){ universal++; if (hasParticular) grounded++; }
      if (PARADOX.test(l)) paradox++;
    }
    const argMarkers = (text.match(/\b(but|however|though|although|yet|still|nevertheless|instead|whereas|except|even though|despite|while)\b/gi)||[]).length;
    const causal = (text.match(CAUSAL)||[]).length;
    const cond = (text.match(COND)||[]).length;
    const rq = (text.match(RQ)||[]).length;

    const f = {
      t4_phil_sequentialFlow: seqStart / nL,
      t4_phil_connectives: connect / nT,
      t4_phil_argMarkers: argMarkers / nL,
      t4_phil_conditionals: cond / nL,
      t4_phil_causal: causal / nL,
      t4_phil_paradox: paradox / nL,
      t4_phil_rhetoricalQ: rq / nL,
      t4_phil_groundedIdea: grounded / nL,
      t4_phil_bareUniversal: (universal - grounded) / nL,
    };

    const bits = [];
    bits.push(f.t4_phil_sequentialFlow > 0.15 ? 'lines follow in logical order' : 'lines stand alone (little logical flow)');
    bits.push((f.t4_phil_argMarkers + f.t4_phil_causal) > 0.2 ? 'argues a tension/cause' : 'states without reasoning');
    if (paradox) bits.push('uses paradox');
    if (rq) bits.push('asks the listener something');
    let tip;
    if (f.t4_phil_sequentialFlow < 0.1) tip = 'connect two lines with a "but/so/because" so the verse reasons, not just lists';
    else if ((f.t4_phil_argMarkers + f.t4_phil_causal) < 0.1) tip = 'add a turn of logic — a contradiction or a consequence';
    else if (f.t4_phil_bareUniversal > 0.1) tip = 'ground a big claim ("everyone/always") in one specific instance';
    else tip = 'the thinking is there — try posing it as a question or paradox';

    return { features: f, report: `Philosopher: ${bits.join(', ')}. ${tip}.`,
      score: clamp01(0.5 + 0.2*(f.t4_phil_bareUniversal*3 - f.t4_phil_sequentialFlow*2 - f.t4_phil_argMarkers - f.t4_phil_causal*2 - f.t4_phil_paradox*3)) };
  }
  function clamp01(x){ return Math.max(0, Math.min(1, x)); }
  const api = { analyze };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.PerspPhil = api;
})();


/* ===== analysis/perspectives/storyteller.js ===== */
/* perspectives/storyteller.js — the STORYTELLER lens: is this a STORY (who/where/when/what-happens)
 * or just atmosphere? AI excels at mood; it struggles to put named people in real places doing
 * things in sequence. All text-only.
 *
 *   Q                                  feature                    hyp.
 *   1 named people/places (proper nouns) t4_story_namedEntities    human↑
 *   2 concrete setting (rooms/streets…)  t4_story_setting          human↑
 *   3 things HAPPEN (action past-tense)  t4_story_action           human↑
 *   4 temporal sequence (then/that night)t4_story_temporalSeq      human↑
 *   5 dialogue / quoted speech           t4_story_dialogue         human↑
 *   6 other characters (he/she/they/name)t4_story_otherChars       human↑
 *   7 concrete time/date/age             t4_story_concreteTime     human↑ (reuse numericReferent)
 *   8 object density (things, not ideas) t4_story_objects          human↑
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof require !== 'undefined' ? globalThis : this);
  const P = G.Prosody || (typeof require !== 'undefined' ? require('../prosody.js') : null);
  const T3 = G.SlopTier3 || (typeof require !== 'undefined' ? safeReq('../tier3_detectors.js') : null);
  function safeReq(p){ try { return require(p); } catch(_) { return null; } }

  const SETTING = new Set(('room rooms street streets town city kitchen bar bars car cars road roads house houses home '+
    'door doors window windows station train trains bus church school yard porch field fields bridge highway diner motel '+
    'apartment bed table floor garden hill beach corner sidewalk gate fence barn store shop counter hallway basement '+
    'attic driveway parking alley curb pavement platform pew booth stool dashboard').split(/\s+/));
  const TEMPORAL = new Set('then after before next later finally suddenly meanwhile soon afterwards afterward yesterday tomorrow morning evening night noon dawn dusk midnight autumn winter summer spring monday tuesday wednesday thursday friday saturday sunday'.split(/\s+/));
  const DIALOGUE_V = new Set('said told asked replied whispered shouted called answered yelled cried screamed murmured muttered'.split(/\s+/));
  const THIRD_OTHER = new Set('he she they him her them his their hers'.split(/\s+/));
  const OBJECT = new Set(('cigarette cigarettes coffee bottle bottles glass keys phone letter letters photograph photo photos '+
    'guitar radio clock ring dress shirt coat shoes boots hat watch knife gun car truck money dollar cards card record '+
    'records suitcase bag jacket gloves scarf umbrella newspaper map ticket envelope').split(/\s+/));

  function analyze(text){
    const L = P.lines(text), nL = Math.max(1, L.length);
    const toks = []; for (const l of L) for (const w of P.words(l)) toks.push(w);
    const nT = Math.max(1, toks.length);

    let setting=0, temporal=0, dialogueV=0, third=0, object=0, past=0;
    for (const w of toks){
      if (SETTING.has(w)) setting++;
      if (TEMPORAL.has(w)) temporal++;
      if (DIALOGUE_V.has(w)) dialogueV++;
      if (THIRD_OTHER.has(w)) third++;
      if (OBJECT.has(w)) object++;
      if (/[a-z]ed$/.test(w) && w.length>3 && P.posLite(w)==='V') past++;   // action narration
    }
    // dialogue: quoted speech OR dialogue verbs
    const quotes = (text.match(/["“”]/g)||[]).length;
    const dialogue = (dialogueV + quotes/2) / nL;

    // named entities (mid-line proper nouns) + concrete time via tier3
    let named = 0;
    for (const l of L){ const raw=l.split(/\s+/); for (let i=1;i<raw.length;i++){ if (/^[A-Z][a-z]{2,}$/.test(raw[i]) && !/^(I|Im|Id|Ive|Ill)$/.test(raw[i])) named++; } }
    const concreteTime = T3 && T3.numericReferentCount ? T3.numericReferentCount(text)/nL : 0;

    const f = {
      t4_story_namedEntities: named / nL,
      t4_story_setting: setting / nT,
      t4_story_action: past / nT,
      t4_story_temporalSeq: temporal / nL,
      t4_story_dialogue: dialogue,
      t4_story_otherChars: third / nT,
      t4_story_concreteTime: concreteTime,
      t4_story_objects: object / nT,
    };

    const bits = [];
    bits.push(f.t4_story_setting > 0.03 || named > 0 ? 'has a place/people' : 'no real place or characters');
    bits.push(f.t4_story_action > 0.03 ? 'things happen (action)' : 'mostly states of being, little action');
    if (f.t4_story_dialogue > 0.1) bits.push('has voices/dialogue');
    if (f.t4_story_temporalSeq > 0.2) bits.push('moves through time');
    let tip;
    if (named === 0 && f.t4_story_setting < 0.02) tip = 'put it somewhere real — a named place, a specific room';
    else if (f.t4_story_action < 0.02) tip = 'let something HAPPEN — an action, not just a feeling';
    else if (f.t4_story_dialogue < 0.05) tip = 'add a line of what someone actually said';
    else tip = 'the scene is alive — give it one more concrete object to hold onto';

    return { features: f, report: `Storyteller: ${bits.join(', ')}. ${tip}.`,
      score: clamp01(0.5 - 0.18*(f.t4_story_namedEntities*2 + f.t4_story_setting*5 + f.t4_story_action*5 + f.t4_story_dialogue + f.t4_story_concreteTime*3 - 1)) };
  }
  function clamp01(x){ return Math.max(0, Math.min(1, x)); }
  const api = { analyze };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.PerspStory = api;
})();


/* ===== analysis/perspectives.js ===== */
/* perspectives.js — aggregator for the 6 craft-perspective lenses (tier-4).
 * Returns { features: {...all t4_*}, perspectives: { rapper:{report,score}, ... } }.
 * Works in Node (training: require) and browser (inference: globalThis.Persp*). The flat `features`
 * merge into denseDict (pipeline_tier3 + v2-engine) so the trained model weights them; the per-lens
 * report/score drive the craft panel.
 */
'use strict';
(function () {
  const G = (typeof globalThis !== 'undefined') ? globalThis : (typeof require !== 'undefined' ? globalThis : this);
  function req(p){ try { return require(p); } catch(_) { return null; } }
  const NODE = (typeof require !== 'undefined');
  const LENS = {
    rapper:       G.PerspRapper || (NODE ? req('./perspectives/rapper.js') : null),
    poet:         G.PerspPoet   || (NODE ? req('./perspectives/poet.js') : null),
    wit:          G.PerspWit    || (NODE ? req('./perspectives/wit.js') : null),
    psychologist: G.PerspPsych  || (NODE ? req('./perspectives/psychologist.js') : null),
    philosopher:  G.PerspPhil   || (NODE ? req('./perspectives/philosopher.js') : null),
    storyteller:  G.PerspStory  || (NODE ? req('./perspectives/storyteller.js') : null),
  };

  function analyze(text){
    const features = {}; const perspectives = {};
    for (const name in LENS){
      const lens = LENS[name]; if (!lens || !lens.analyze) continue;
      let r; try { r = lens.analyze(text); } catch (e) { continue; }
      if (r && r.features) for (const k in r.features){ const v = r.features[k]; features[k] = (typeof v === 'number' && isFinite(v)) ? v : 0; }
      if (r) perspectives[name] = { report: r.report || '', score: r.score };
    }
    return { features, perspectives };
  }
  // just the flat feature dict (for denseDict)
  function features(text){ return analyze(text).features; }

  const api = { analyze, features, LENS };
  if (typeof module !== 'undefined' && module.exports) module.exports = api;
  G.SlopPerspectives = api;
})();

